// 2.7.1 | 2021-12-08 | raj  | DFCT0010613 - DEA: "Personal Template Designers" can view any template in the system
//                             This business rule was not active.  
//                             Look at the notes in the defect for information about file history
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	var originalQuery = current.getEncodedQuery() + '';
    var myProcess = new tasking_System_Settings_Scripts().getMyTemplateFilter(false);
    var ouProcess = new tasking_System_Settings_Scripts().getOUTemplateFilter(false);
    var globalProcess = new tasking_System_Settings_Scripts().getGlobalTemplateFilter(false);
	var addFilter = '';
	var addNotFilter = '';

	// Get all Nots
	if(myProcess == ''){
		addNotFilter = 'process_level!=my_process';
	} 
	if(ouProcess == ''){
		addNotFilter = addNotFilter != '' ? addNotFilter + '^' : addNotFilter;
		addNotFilter = addNotFilter + 'process_level!=ou_process';
	}	
	if(globalProcess == ''){
		addNotFilter = addNotFilter != '' ? addNotFilter + '^' : addNotFilter;
		addNotFilter = addNotFilter + 'process_level!=global_process';
	}
	// used below when need to add with ^ after
	var includeNot = ((addNotFilter != '') ? addNotFilter + '^' : '' );


	// use this to determine if NO levels were found and add the not at the end if no levels were found
	var levelFound = false;

	// if my process exists - add not of Global and OU with My Process to original
	if(myProcess != ''){
		var addMy = '';
		if ((originalQuery == '') && (addNotFilter == '')) {
			addMy = myProcess;
		} else if(originalQuery == ''){
			addMy = addNotFilter + '^' + myProcess;
		} else if(addNotFilter == ''){
			addMy = '^' + myProcess;				  
		} 
		current.addEncodedQuery(addMy);
		levelFound = true;
	}
	// if OU process exists - and NOT my, then add OU qury and Not of my and global to the original
	//                        and my, then add NQ with OU qury and Not of my and global to the original
	if(ouProcess != ''){
		var addOU = '';
		if ((originalQuery == '') && (addNotFilter == '') && (myProcess == '')){
			addOU = ouProcess;
		} else if ((originalQuery == '') && (myProcess == '')){
			addOU = addNotFilter + '^' + ouProcess;
		} else {
			if(originalQuery != ''){
				addOU = '^NQ' + originalQuery + '^' + includeNot + ouProcess;
			} else{
				addOU = '^NQ' + includeNot + ouProcess;
			}
		}
		current.addEncodedQuery(addOU);
		levelFound = true;
	}
	// if global process exists - and NOT my and not OU, then add global qury and Not of my and OU to the original
	//                            and my or OU, then add NQ with global qury and Not of my and OU to the original
	if(globalProcess != ''){
		var addGlobal = '';
		if ((originalQuery == '') && (addNotFilter == '') && (myProcess == '') && (ouProcess == '')){
			addGlobal = globalProcess;
		} else if ((originalQuery == '') && (myProcess == '') && (ouProcess == '')){
			addGlobal = addNotFilter + '^' + globalProcess;
		} else {
			if(originalQuery!= ''){
				addGlobal = '^NQ' + originalQuery + '^' + includeNot + globalProcess;
			} else{
				addGlobal = '^NQ' + includeNot +  globalProcess;
			}
		}
		current.addEncodedQuery(addGlobal);
		levelFound = true;
	}
	// add to original or add as only (if only, then the user won't see any templates)
	if(!levelFound){
		current.addEncodedQuery(addNotFilter);
	}
})(current, previous);
